From debd59396b0678fdcdbfecc3a63166a049f22863 Mon Sep 17 00:00:00 2001
From: baur <baurzhansahariev@gmail.com>
Date: Fri, 5 Jul 2024 17:53:21 +0500
Subject: [PATCH] Fix parsing of char columns in foreign tables result set

Fixes regression introduced in https://github.com/crate/crate/commit/70ddc1f6eab604ab4220b15c81dfd19a33c621dc
---
 docs/appendices/release-notes/5.7.3.rst       |  3 ++
 .../java/io/crate/types/ResultSetParser.java  |  9 ++--
 .../io/crate/types/ResultSetParserTest.java   | 43 +++++++++++++++++++
 .../crate/testing/SQLTransportExecutor.java   |  7 +++
 4 files changed, 59 insertions(+), 3 deletions(-)
 create mode 100644 server/src/test/java/io/crate/types/ResultSetParserTest.java

diff --git a/docs/appendices/release-notes/5.7.3.rst b/docs/appendices/release-notes/5.7.3.rst
index 49516a661a..5e0bc3c03c 100644
--- a/docs/appendices/release-notes/5.7.3.rst
+++ b/docs/appendices/release-notes/5.7.3.rst
@@ -94,4 +94,7 @@ Fixes

       SELECT * from t1 JOIN t2 ON (t1.a >= 1) = ((t1.a = t1.a) AND (t2.b <= t2.b))

+- Fixed a regression introduced in 5.7.2 that caused ``SQLParseException`` when
+  selecting columns of type ``char`` from a foreign table.
+

diff --git a/server/src/main/java/io/crate/types/ResultSetParser.java b/server/src/main/java/io/crate/types/ResultSetParser.java
index 42b4d3027c..063256bb54 100644
--- a/server/src/main/java/io/crate/types/ResultSetParser.java
+++ b/server/src/main/java/io/crate/types/ResultSetParser.java
@@ -80,11 +80,14 @@ public class ResultSetParser {
                 return PgOidVectorType.listFromOidVectorString(textval);
             }
             case "char":
-                String strValue = resultSet.getString(columnIndex);
-                if (strValue == null) {
+                // It's NOT char(1) which is actually "character".
+                // It's char with OID 18, ie single byte "char" which can store single ASCII character.
+                // See also https://www.postgresql.org/docs/15/datatype-character.html#DATATYPE-CHARACTER-SPECIAL-TABLE
+                String str = resultSet.getString(columnIndex);
+                if (str == null) {
                     return null;
                 }
-                return Byte.valueOf(strValue);
+                return str;
             case "byte":
                 value = resultSet.getByte(columnIndex);
                 break;
diff --git a/server/src/test/java/io/crate/types/ResultSetParserTest.java b/server/src/test/java/io/crate/types/ResultSetParserTest.java
new file mode 100644
index 0000000000..7f603888d8
