+package io.crate.types;
+
+import static org.assertj.core.api.Assertions.assertThat;
+import static org.mockito.ArgumentMatchers.anyInt;
+import static org.mockito.Mockito.mock;
+import static org.mockito.Mockito.when;
+
+import java.sql.ResultSet;
+
+import org.junit.Test;
+
+public class ResultSetParserTest {
+
+    @Test
+    public void test_can_query_char_column_via_jdbc_from_foreign_table() throws Exception {
+        // Concrete example would be `select prokind from remote_pg_proc`
+        ResultSet resultSet = mock(ResultSet.class);
+        when(resultSet.getString(anyInt())).thenReturn("f");
+        assertThat(ResultSetParser.getObject(resultSet, 1, "char")).isEqualTo("f");
+    }
+
+}
diff --git a/server/src/testFixtures/java/io/crate/testing/SQLTransportExecutor.java b/server/src/testFixtures/java/io/crate/testing/SQLTransportExecutor.java
index 9b9cdb6bc4..c4e9506f29 100644
--- a/server/src/testFixtures/java/io/crate/testing/SQLTransportExecutor.java
+++ b/server/src/testFixtures/java/io/crate/testing/SQLTransportExecutor.java
@@ -430,6 +430,13 @@ public class SQLTransportExecutor {
                     Object value;
                     String typeName = metadata.getColumnTypeName(i + 1);
                     value = getObject(resultSet, i, typeName);
+                    if (typeName.equals("char") && value != null) {
+                        // ResultSetParser is dedicated to deal with Postgres specific "char" type which can be single ASCII character.
+                        // This code is also used in tests to get results via JDBC which is not necessarily bound to PG logic.
+                        // Hence, cancel PG specific logic here.
+                        assert value instanceof String;
+                        value = Byte.parseByte((String) value);
+                    }
                     row[i] = value;
                 }
                 rows.add(row);
